    27→/** Jam closure represention for programs with symbolic variables*/
    28→class VarClosure extends JamFun implements Closure {
    29→  private Map map;
    30→  private SymEvaluator eval;
    31→  VarClosure(Map m, SymEvaluator e) { map = m; eval = e; }
    32→  public int arity() { return map.vars().length; }
    33→  public JamVal apply(JamVal[] args) {
    34→    Variable[] vars = map.vars();
    35→    VarEnv newEnv = eval.env();
    36→    int n = vars.length;
    37→    if (n != args.length) throw new EvalException("closure " + this + " applied to " + 
    38→       args.length + " arguments instead of " + n + " arguments");
    39→    for (int i = n-1 ; i >= 0; i--) 
    40→      newEnv = newEnv.cons(new Binding(vars[i],args[i]));
    41→    return map.body().accept((SymASTVisitor<JamVal>) eval.newEvalVisitor(newEnv));
    42→  }                                                 
    43→  public <RtnType> RtnType accept(FunVisitor<RtnType> jfv) { return jfv.forClosure(this); }
    44→  public String toString() { return "VarClosure<" + map + ">"; }
    45→}
