   487→      new SyntaxException("Attempt to build Defs[] with mismatched Variable[] " + vars + " and SymAST[] " + exps);
   488→    Def[] newDefs = new Def[n];
   489→    for (int i = 0; i < n; i++) newDefs[i] = new Def(vars[i], exps[i]);
   490→    return newDefs;
   491→  }
   492→  
   493→  static Def[] tail(Def[] in) {
   494→    int n = in.length;
   495→    Def[] out = new Def[n-1];
   496→    for (int i = 0; i < n-1; i++) out[i] = in[i+1];
   497→    return out;
   498→  }
   499→}
